using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;

public static class DynamicSqlFunction
{
    [FunctionName("DynamicSqlQuery")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        log.LogInformation("C# HTTP trigger function processed a request.");

        string connectionString = Environment.GetEnvironmentVariable("SqlDbConnection");
        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("SQL Database connection string 'SqlDbConnection' is not configured.");
        }

        List<string> whereClauses = new List<string>();
        List<SqlParameter> parameters = new List<SqlParameter>();

        // Example: Filter by product name (partial match)
        string name = req.Query["name"];
        if (!string.IsNullOrEmpty(name))
        {
            whereClauses.Add("ProductName LIKE @name");
            parameters.Add(new SqlParameter("@name", SqlDbType.NVarChar) { Value = $"%{name}%" });
        }

        // Example: Filter by category (exact match)
        string category = req.Query["category"];
        if (!string.IsNullOrEmpty(category))
        {
            whereClauses.Add("Category = @category");
            parameters.Add(new SqlParameter("@category", SqlDbType.NVarChar) { Value = category });
        }

        // Example: Filter by minimum price
        if (double.TryParse(req.Query["minPrice"], out double minPrice))
        {
            whereClauses.Add("Price >= @minPrice");
            parameters.Add(new SqlParameter("@minPrice", SqlDbType.Decimal) { Value = minPrice });
        }

        // Example: Filter by maximum price
        if (double.TryParse(req.Query["maxPrice"], out double maxPrice))
        {
            whereClauses.Add("Price <= @maxPrice");
            parameters.Add(new SqlParameter("@maxPrice", SqlDbType.Decimal) { Value = maxPrice });
        }

        string baseQuery = "SELECT Id, ProductName, Category, Price, CreatedDate FROM Products";
        string sqlQuery = baseQuery;

        if (whereClauses.Any())
        {
            sqlQuery += " WHERE " + string.Join(" AND ", whereClauses);
        }

        // Add ORDER BY for consistent results
        sqlQuery += " ORDER BY ProductName ASC, Id ASC";

        List<Dictionary<string, object>> results = new List<Dictionary<string, object>>();

        try
